// ===== MATCHA — "it's in everything now" : kinetic type video =====
// Appended after animations.jsx (Stage, Sprite, useSprite, useTime, Easing, clamp all in scope).

const CREAM = '#EFECDD';
const INK   = '#19220F';
const MATCHA= '#7CA64A';
const LIME  = '#CBE85A';
const DEEP  = '#3E5F2A';
const FD = "Anton, sans-serif";              // display
const FM = "'Space Grotesk', sans-serif";    // support / mono-ish

function Bg({ color }) {
  return React.createElement('div', { style: { position:'absolute', inset:0, background: color } });
}

const gpulse = (t, c, w) => Math.exp(-Math.pow((t - c) / w, 2));

// ── S1 cold open ────────────────────────────────────────────────
function ColdOpen() {
  const { localTime, duration } = useSprite();
  const settle = Easing.easeOutExpo(clamp((localTime - 0.08) / 0.7, 0, 1));
  const scale  = 2.5 - 1.5 * settle;
  const rot    = -5 + 5 * settle;
  const op     = clamp(localTime / 0.15, 0, 1);
  const flash  = gpulse(localTime, 0.42, 0.11);
  const kick   = clamp((localTime - 0.55) / 0.4, 0, 1);
  const exit   = localTime > duration - 0.22 ? clamp((localTime - (duration - 0.22)) / 0.22, 0, 1) : 0;
  return (
    <div style={{ position:'absolute', inset:0, opacity:1 - exit, transform:`scale(${1 + 0.25 * exit})`, transformOrigin:'50% 45%' }}>
      <Bg color={CREAM} />
      <div style={{ position:'absolute', inset:0, background:MATCHA, opacity:flash * 0.92, mixBlendMode:'multiply' }} />
      <div style={{ position:'absolute', top:300, left:0, right:0, textAlign:'center', fontFamily:FM, fontWeight:600, fontSize:34, letterSpacing:'0.16em', color:INK, opacity:kick, transform:`translateY(${(1 - kick) * -12}px)` }}>GREEN&nbsp;TEA · POWDERED · UNHINGED</div>
      <div style={{ position:'absolute', inset:0, display:'flex', alignItems:'center', justifyContent:'center' }}>
        <div style={{ fontFamily:FD, fontSize:360, lineHeight:0.9, color:INK, opacity:op, transform:`scale(${scale}) rotate(${rot}deg)`, letterSpacing:'-0.01em' }}>MATCHA</div>
      </div>
      <div style={{ position:'absolute', bottom:330, left:0, right:0, textAlign:'center', fontFamily:FM, fontWeight:500, fontSize:42, color:DEEP, opacity:kick, transform:`translateY(${(1 - kick) * 12}px)` }}>is in everything now →</div>
    </div>
  );
}

// ── S2 "and it's in EVERYTHING" ────────────────────────────────
function EverythingHit() {
  const { localTime, duration } = useSprite();
  const sx     = Easing.easeOutExpo(clamp(localTime / 0.4, 0, 1));
  const scaleX = 0.22 + 0.78 * sx;
  const op     = clamp(localTime / 0.1, 0, 1);
  const top    = clamp((localTime - 0.05) / 0.3, 0, 1);
  const exit   = localTime > duration - 0.12 ? clamp((localTime - (duration - 0.12)) / 0.12, 0, 1) : 0;
  return (
    <div style={{ position:'absolute', inset:0, opacity:1 - exit }}>
      <Bg color={MATCHA} />
      <div style={{ position:'absolute', inset:0, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', gap:14 }}>
        <div style={{ fontFamily:FM, fontWeight:600, fontSize:48, letterSpacing:'0.2em', color:INK, opacity:top }}>…AND IT'S IN</div>
        <div style={{ fontFamily:FD, fontSize:240, color:INK, opacity:op, transform:`scaleX(${scaleX})`, transformOrigin:'center', lineHeight:0.82, letterSpacing:'-0.02em', textAlign:'center' }}>EVERY<br/>THING</div>
      </div>
    </div>
  );
}

// ── S3 montage cards ───────────────────────────────────────────
const CARDS = [
  { word:'LATTES',     label:'the gateway drug',    bg:CREAM,  fg:INK,   accent:MATCHA, size:300 },
  { word:'ICE\nCREAM', label:'soft-serve summer',   bg:MATCHA, fg:INK,   accent:LIME,   size:250 },
  { word:'CROISSANTS', label:'the bakery flex',     bg:INK,    fg:CREAM, accent:LIME,   size:175 },
  { word:'KIT\nKATS',  label:'japan-import core',   bg:LIME,   fg:INK,   accent:DEEP,   size:250 },
  { word:'TIRAMISU',   label:'the 2025 plot twist', bg:CREAM,  fg:INK,   accent:MATCHA, size:205 },
  { word:'COLD\nFOAM', label:'your order, upgraded',bg:MATCHA, fg:INK,   accent:CREAM,  size:270 },
  { word:'SKINCARE',   label:'now on your face',    bg:INK,    fg:LIME,  accent:CREAM,  size:200 },
];

function Card({ word, label, idx, bg, fg, accent, size }) {
  const { localTime, duration } = useSprite();
  const inb   = Easing.easeOutBack(clamp(localTime / 0.3, 0, 1));
  const scale = 0.55 + 0.45 * inb;
  const exitStart = duration - 0.16;
  let exOp = 1, exX = 0;
  if (localTime > exitStart) { const t = Easing.easeInCubic(clamp((localTime - exitStart) / 0.16, 0, 1)); exOp = 1 - t; exX = -80 * t; }
  const labW  = Easing.easeOutExpo(clamp((localTime - 0.08) / 0.3, 0, 1));
  const shake = Math.sin(localTime * 34) * (localTime < 0.26 ? 4 : 0.6);
  return (
    <div style={{ position:'absolute', inset:0, opacity:exOp, transform:`translateX(${exX}px)` }}>
      <Bg color={bg} />
      <div style={{ position:'absolute', top:255, left:72, fontFamily:FM, fontWeight:700, fontSize:42, color:accent }}>{String(idx).padStart(2,'0')}</div>
      <div style={{ position:'absolute', top:262, right:72, fontFamily:FM, fontWeight:600, fontSize:30, letterSpacing:'0.14em', color:fg, opacity:0.5 }}>MATCHA</div>
      <div style={{ position:'absolute', inset:0, display:'flex', alignItems:'center', justifyContent:'center' }}>
        <div style={{ fontFamily:FD, fontSize:size, lineHeight:0.84, color:fg, textAlign:'center', whiteSpace:'pre-line', transform:`scale(${scale}) translateX(${shake}px)`, letterSpacing:'-0.015em' }}>{word}</div>
      </div>
      <div style={{ position:'absolute', bottom:300, left:'50%', transform:'translateX(-50%)', display:'flex', flexDirection:'column', alignItems:'center', gap:20 }}>
        <div style={{ height:12, width:240 * labW, background:accent }} />
        <div style={{ fontFamily:FM, fontWeight:600, fontSize:40, letterSpacing:'0.04em', color:fg, opacity:clamp((localTime - 0.12) / 0.3, 0, 1) }}>{label}</div>
      </div>
    </div>
  );
}

// ── S4 Kyoto → For You Page ────────────────────────────────────
function KyotoFeed() {
  const { localTime, duration } = useSprite();
  const l1   = Easing.easeOutExpo(clamp(localTime / 0.5, 0, 1));
  const l2   = Easing.easeOutExpo(clamp((localTime - 0.55) / 0.5, 0, 1));
  const arr  = clamp((localTime - 0.5) / 0.3, 0, 1);
  const exit = localTime > duration - 0.18 ? clamp((localTime - (duration - 0.18)) / 0.18, 0, 1) : 0;
  return (
    <div style={{ position:'absolute', inset:0, opacity:1 - exit }}>
      <Bg color={CREAM} />
      <div style={{ position:'absolute', inset:0, display:'flex', flexDirection:'column', justifyContent:'center', padding:'0 90px', gap:34 }}>
        <div style={{ fontFamily:FM, fontWeight:600, fontSize:40, letterSpacing:'0.14em', color:DEEP, opacity:l1 }}>900 YEARS IN THE MAKING</div>
        <div style={{ fontFamily:FD, fontSize:152, lineHeight:0.92, color:INK, transform:`translateX(${(1 - l1) * -90}px)`, opacity:l1 }}>FROM A KYOTO<br/>TEA CEREMONY</div>
        <div style={{ fontFamily:FD, fontSize:90, color:MATCHA, opacity:arr, lineHeight:1 }}>↓</div>
        <div style={{ fontFamily:FD, fontSize:152, lineHeight:0.92, color:DEEP, transform:`translateX(${(1 - l2) * 90}px)`, opacity:l2 }}>TO YOUR<br/>FOR YOU PAGE</div>
      </div>
    </div>
  );
}

// ── S5 however you take it (pills) ─────────────────────────────
const PILLS = [
  { t:'ICED',             fill:INK,    fg:CREAM },
  { t:'OAT MILK',         fill:LIME,   fg:INK   },
  { t:'EXTRA SHOT',       fill:CREAM,  fg:INK, bd:INK },
  { t:'CEREMONIAL',       fill:INK,    fg:LIME  },
  { t:'2 PUMPS VANILLA',  fill:DEEP,   fg:CREAM },
  { t:'EXTRA HOT',        fill:CREAM,  fg:INK, bd:INK },
];
function HowYouTakeIt() {
  const { localTime, duration } = useSprite();
  const head = clamp(localTime / 0.3, 0, 1);
  const exit = localTime > duration - 0.16 ? clamp((localTime - (duration - 0.16)) / 0.16, 0, 1) : 0;
  return (
    <div style={{ position:'absolute', inset:0, opacity:1 - exit }}>
      <Bg color={MATCHA} />
      <div style={{ position:'absolute', top:320, left:0, right:0, textAlign:'center', fontFamily:FM, fontWeight:700, fontSize:50, letterSpacing:'0.1em', color:INK, opacity:head, transform:`translateY(${(1 - head) * -14}px)` }}>HOWEVER YOU TAKE IT</div>
      <div style={{ position:'absolute', inset:0, display:'flex', flexWrap:'wrap', alignContent:'center', justifyContent:'center', gap:'28px 26px', padding:'0 110px' }}>
        {PILLS.map((p, i) => {
          const st = 0.32 + i * 0.13;
          const a  = Easing.easeOutBack(clamp((localTime - st) / 0.32, 0, 1));
          const o  = clamp((localTime - st) / 0.18, 0, 1);
          return <div key={i} style={{ fontFamily:FD, fontSize:78, padding:'18px 44px 8px', borderRadius:90, background:p.fill, color:p.fg, border:p.bd ? `5px solid ${p.bd}` : 'none', transform:`scale(${0.5 + 0.5 * a})`, opacity:o, letterSpacing:'0.01em' }}>{p.t}</div>;
        })}
      </div>
    </div>
  );
}

// ── S6 closer ──────────────────────────────────────────────────
function Closer() {
  const { localTime } = useSprite();
  const a         = Easing.easeOutExpo(clamp(localTime / 0.5, 0, 1));
  const green     = Easing.easeOutBack(clamp((localTime - 0.45) / 0.5, 0, 1));
  const underline = clamp((localTime - 0.95) / 0.4, 0, 1);
  const tag       = clamp((localTime - 1.15) / 0.5, 0, 1);
  const breathe   = 1 + Math.sin(localTime * 1.6) * 0.012;
  return (
    <div style={{ position:'absolute', inset:0 }}>
      <Bg color={INK} />
      <div style={{ position:'absolute', inset:0, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center' }}>
        <div style={{ fontFamily:FD, fontSize:165, lineHeight:0.88, color:CREAM, textAlign:'center', opacity:a, transform:`translateY(${(1 - a) * 30}px)` }}>EVERYTHING'S<br/>BETTER</div>
        <div style={{ position:'relative', marginTop:12, transform:`scale(${(0.6 + 0.4 * clamp(green,0,1)) * breathe})` }}>
          <div style={{ fontFamily:FD, fontSize:300, lineHeight:0.85, color:LIME, opacity:clamp(green,0,1) }}>GREEN</div>
          <div style={{ position:'absolute', left:0, bottom:30, height:14, width:`${underline * 100}%`, background:MATCHA }} />
        </div>
      </div>
      <div style={{ position:'absolute', bottom:235, left:0, right:0, textAlign:'center', fontFamily:FM, fontWeight:500, fontSize:38, letterSpacing:'0.06em', color:'rgba(239,236,221,0.55)', opacity:tag }}>— matcha, probably</div>
    </div>
  );
}

// ── timecode tagger (for commenting) ───────────────────────────
function Timecode() {
  const t = useTime();
  const sec = Math.floor(t);
  React.useEffect(() => {
    const root = document.querySelector('[data-video-root]');
    if (root) root.dataset.screenLabel = sec + 's';
  }, [sec]);
  return null;
}

// ── root ───────────────────────────────────────────────────────
function MatchaVideo() {
  return (
    <Stage width={1080} height={1920} duration={15} background={CREAM} persistKey="matcha">
      <Timecode />
      <Sprite start={0}    end={2.5}><ColdOpen /></Sprite>
      <Sprite start={2.5}  end={3.3}><EverythingHit /></Sprite>
      {CARDS.map((c, i) => { const s = 3.3 + i * 0.85; return (
        <Sprite key={i} start={s} end={s + 0.85}><Card word={c.word} label={c.label} idx={i + 1} bg={c.bg} fg={c.fg} accent={c.accent} size={c.size} /></Sprite>
      ); })}
      <Sprite start={9.25}  end={11.1}><KyotoFeed /></Sprite>
      <Sprite start={11.1}  end={12.95}><HowYouTakeIt /></Sprite>
      <Sprite start={12.95} end={15}><Closer /></Sprite>
    </Stage>
  );
}
window.MatchaVideo = MatchaVideo;

